// Memory Consolidation — summarize daily interactions into long-term memory with vector embeddings
//
// Flow:
// 1. Load cursor (last processed memory_daily ID) from heartbeat_config
// 2. Load all memory_daily entries since cursor
// 3. Skip if no new entries
// 4. Summarize with Claude (Haiku — cheap + fast)
// 5. Generate embedding via configurable provider
// 6. Save summary + embedding to memory_long
// 7. Update cursor
// 8. Clean up old reminders (delivered > 30 days ago)

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const http = this.helpers.httpRequest;

// --- Helper: PostgREST request ---
async function pgrest(method, path, body, extraHeaders = {}) {
  const opts = {
    method,
    url: `${SUPABASE_URL}${path}`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Content-Type': 'application/json',
      ...extraHeaders
    },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  };
  if (body) opts.body = body;
  const res = await http(opts);
  return res.body;
}

// --- Helper: Generate embedding via configurable provider (config from DB) ---
async function getEmbedding(text) {
  const cfgResp = await pgrest('GET', '/rest/v1/tools_config?tool_name=eq.embedding&select=config,enabled');
  const cfg = (Array.isArray(cfgResp) && cfgResp.length > 0 && cfgResp[0].enabled) ? cfgResp[0].config : null;
  if (!cfg || !cfg.api_key) return null;
  const provider = cfg.provider || 'openai';
  const apiKey = cfg.api_key;
  const model = cfg.model || 'text-embedding-3-small';

  try {
    if (provider === 'openai') {
      const data = await http({
        method: 'POST',
        url: 'https://api.openai.com/v1/embeddings',
        headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
        body: { model, input: text }
      });
      return data.data[0].embedding;
    }
    if (provider === 'voyage') {
      const data = await http({
        method: 'POST',
        url: 'https://api.voyageai.com/v1/embeddings',
        headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
        body: { model: model || 'voyage-3-lite', input: [text] }
      });
      return data.data[0].embedding;
    }
    if (provider === 'ollama') {
      const ollamaUrl = cfg.ollama_url || 'http://localhost:11434';
      const data = await http({
        method: 'POST',
        url: `${ollamaUrl}/api/embed`,
        headers: { 'Content-Type': 'application/json' },
        body: { model: model || 'nomic-embed-text', input: text }
      });
      return data.embeddings[0];
    }
  } catch (e) {
    return null;
  }
  return null;
}

// --- Helper: Summarize with LLM (provider-agnostic, config from DB) ---
const SUMMARIZE_PROMPT = 'Summarize the following conversation log into key facts, decisions, preferences, and context worth remembering long-term. Be concise and structured. Output plain text, no markdown headers.';

async function summarize(text) {
  // 1. Try llm_provider config (new installs)
  const llmResp = await pgrest('GET', '/rest/v1/tools_config?tool_name=eq.llm_provider&select=config,enabled');
  let cfg = (Array.isArray(llmResp) && llmResp.length > 0 && llmResp[0].enabled) ? llmResp[0].config : null;

  // 2. Fallback to legacy 'anthropic' config (existing installs)
  if (!cfg) {
    const legacyResp = await pgrest('GET', '/rest/v1/tools_config?tool_name=eq.anthropic&select=config');
    const legacyKey = (Array.isArray(legacyResp) && legacyResp.length > 0) ? legacyResp[0].config.api_key : null;
    if (legacyKey) {
      cfg = { provider: 'anthropic', endpoint: 'https://api.anthropic.com/v1/messages', model: 'claude-haiku-4-5-20251001', api_key: legacyKey };
    }
  }

  if (!cfg || !cfg.api_key) throw new Error('No LLM provider configured in tools_config (set llm_provider or anthropic)');

  // 3. Provider dispatch
  if (cfg.provider === 'anthropic') {
    // Anthropic Messages API
    const data = await http({
      method: 'POST',
      url: cfg.endpoint || 'https://api.anthropic.com/v1/messages',
      headers: { 'x-api-key': cfg.api_key, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
      body: { model: cfg.model || 'claude-haiku-4-5-20251001', max_tokens: 1024, system: SUMMARIZE_PROMPT, messages: [{ role: 'user', content: text }] }
    });
    if (data.error) throw new Error(`LLM API error: ${data.error.message}`);
    return data.content[0].text;
  } else {
    // OpenAI-compatible (OpenAI, OpenRouter, Ollama, DeepSeek, Gemini, etc.)
    const headers = { 'Content-Type': 'application/json' };
    if (cfg.api_key && cfg.api_key !== 'not-needed' && cfg.api_key !== 'ollama') {
      headers['Authorization'] = `Bearer ${cfg.api_key}`;
    }
    const data = await http({
      method: 'POST',
      url: cfg.endpoint,
      headers,
      body: { model: cfg.model, max_tokens: 1024, messages: [{ role: 'system', content: SUMMARIZE_PROMPT }, { role: 'user', content: text }] }
    });
    if (data.error) throw new Error(`LLM API error: ${JSON.stringify(data.error)}`);
    return data.choices[0].message.content;
  }
}

// === Main Logic ===

// 1. Load cursor
let cursor = 0;
try {
  const cursorData = await pgrest('GET', '/rest/v1/heartbeat_config?check_name=eq.memory_consolidation&select=config');
  if (Array.isArray(cursorData) && cursorData.length > 0 && cursorData[0].config && cursorData[0].config.last_id) {
    cursor = cursorData[0].config.last_id;
  }
} catch (e) {
  // No cursor yet — start from 0
}

// 2. Load new memory_daily entries
const entries = await pgrest('GET', `/rest/v1/memory_daily?id=gt.${cursor}&order=id.asc`);
if (!Array.isArray(entries) || entries.length === 0) {
  return [{ json: { status: 'no_new_entries', cursor } }];
}

// 3. Group entries by date
const byDate = {};
for (const entry of entries) {
  const d = entry.date || 'unknown';
  if (!byDate[d]) byDate[d] = [];
  byDate[d].push(entry);
}

// 4. Process each date group
const results = [];
let maxId = cursor;

for (const [date, dayEntries] of Object.entries(byDate)) {
  const text = dayEntries.map(e => `[${e.role}] ${e.content}`).join('\n');

  // Skip very short entries (less than 50 chars total)
  if (text.length < 50) {
    const dayMaxId = Math.max(...dayEntries.map(e => e.id));
    if (dayMaxId > maxId) maxId = dayMaxId;
    results.push({ date, entries: dayEntries.length, skipped: true, reason: 'too_short' });
    continue;
  }

  // Summarize with Claude
  const summary = await summarize(text);

  // Generate embedding
  const embedding = await getEmbedding(summary);

  // Save to memory_long
  const saveBody = {
    content: summary,
    category: 'consolidated',
    importance: 7,
    metadata: { source: 'consolidation', date, entry_count: dayEntries.length }
  };
  if (embedding) saveBody.embedding = JSON.stringify(embedding);

  await pgrest('POST', '/rest/v1/memory_long', saveBody, { 'Prefer': 'return=minimal' });

  const dayMaxId = Math.max(...dayEntries.map(e => e.id));
  if (dayMaxId > maxId) maxId = dayMaxId;

  results.push({ date, entries: dayEntries.length, summarized: true, vectorized: !!embedding });
}

// 5. Update cursor
await pgrest('PATCH', '/rest/v1/heartbeat_config?check_name=eq.memory_consolidation', {
  config: { last_id: maxId, last_run: new Date().toISOString() }
});

// 6. Clean up old reminders (delivered more than 30 days ago)
const cutoff = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
await pgrest('DELETE', `/rest/v1/reminders?reminded_at=not.is.null&reminded_at=lt.${cutoff}`);

return [{ json: { status: 'completed', processed: results, new_cursor: maxId } }];
